  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasInitiatives ?child ; p:hasCommunity_Development_Corporations ?parent . } GROUP BY ?child }
  ?child p:initiative_name ?initiative_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Community_Development_Corporations } }
  FILTER(?nf = ?total)
